import os
import json
import argparse

# Configuration
START_DIRECTORY = '/var/www/homeserver'  # Default directory to map
OUTPUT_FILE = 'filehierarchy.json'  # Default output file
MAX_DEPTH = 4  # Default depth (-1 means no limit)
ALLOWED_EXTENSIONS = {'.html', '.json', '.md', '.txt', '.js', '.py', '.css', '.ini'}

def get_file_hierarchy(startpath, max_depth):
    def recurse(current_path, current_depth):
        if max_depth != -1 and current_depth > max_depth:
            return {}

        hierarchy = {}
        for item in os.listdir(current_path):
            item_path = os.path.join(current_path, item)
            if os.path.isdir(item_path):
                sub_hierarchy = recurse(item_path, current_depth + 1)
                if sub_hierarchy:  # Only include non-empty directories
                    hierarchy[item] = sub_hierarchy
            elif os.path.splitext(item)[1].lower() in ALLOWED_EXTENSIONS:
                hierarchy[item] = {
                "type": "file",
                "size": os.path.getsize(item_path),
                    }
        return hierarchy

    return recurse(startpath, 0)

def save_hierarchy_to_json(hierarchy, filename):
    try:
        with open(filename, 'w') as json_file:
            json.dump(hierarchy, json_file, indent=4)
        print(f"File hierarchy saved to: {filename}")
    except IOError as e:
        print(f"Error writing to file {filename}: {e}")
        raise

if __name__ == "__main__":
    parser = argparse.ArgumentParser(description='Generate file hierarchy JSON.')
    parser.add_argument('--dir', default=START_DIRECTORY, help='Directory to map')
    parser.add_argument('--output', default=OUTPUT_FILE, help='Output JSON file name')
    parser.add_argument('--depth', type=int, default=MAX_DEPTH, help='Max depth to traverse (-1 for no limit)')

    args = parser.parse_args()

    # Ensure the output file is placed in the mapped directory
    output_path = os.path.join(args.dir, args.output)

    file_hierarchy = get_file_hierarchy(args.dir, args.depth)

    # This will overwrite the file if it already exists
    save_hierarchy_to_json(file_hierarchy, output_path)

