# Integration tests
class TestServerSetupIntegration(unittest.TestCase):
    @classmethod
    def setUpClass(cls):
        cls.server_setup = ServerSetup(mode=ServerMode.TESTING, step_by_step=False, log_file="integration_test.log")

    @patch('serverSetup.subprocess.run')
    def test_full_setup_flow(self, mock_run):
        mock_run.return_value.stdout = "Mock output"
        self.server_setup.run()

        # Assert that all major setup steps were called
        expected_calls = [
            'install_base_packages',
            'custom_installers',
            'setup_networking',
            'setup_samba',
            'setup_user',
            'setup_technitium',
            'setup_kea',
            'setup_nodejs',
            'setup_apache2',
            'setup_media_group',
            'setup_mariadb',
            'setup_jellyfin',
            'setup_piwigo',
            'setup_prometheus',
            'setup_grafana'
        ]

        for call in expected_calls:
            self.assertTrue(any(call in str(c) for c in mock_run.mock_calls), f"{call} was not called")

    @patch('serverSetup.requests.get')
    @patch('serverSetup.requests.post')
    def test_technitium_api_flow(self, mock_post, mock_get):
        mock_get.return_value.json.return_value = {'token': 'mock_token'}
        mock_post.return_value.status_code = 200

        self.server_setup.setup_technitium()

        # Check that the API calls were made in the correct order
        expected_calls = ['user/login', 'settings/set', 'zones/create', 'records/add', 'apps/enable', 'certificates/upload', 'tsig/add', 'user/logout']
        actual_calls = [call.args[0].split('/')[-1] for call in mock_get.call_args_list + mock_post.call_args_list]

        for expected, actual in zip(expected_calls, actual_calls):
            self.assertEqual(expected, actual, f"Expected {expected} but got {actual}")

def run_tests():
    # Run unit tests
    unit_suite = unittest.TestLoader().loadTestsFromTestCase(TestServerSetup)
    unit_result = unittest.TextTestRunner(verbosity=2).run(unit_suite)

    # Run integration tests
    integration_suite = unittest.TestLoader().loadTestsFromTestCase(TestServerSetupIntegration)
    integration_result = unittest.TextTestRunner(verbosity=2).run(integration_suite)

    # Print summary
    print("\nTest Summary:")
    print(f"Unit Tests: {unit_result.testsRun} run, {len(unit_result.errors)} errors, {len(unit_result.failures)} failures")
    print(f"Integration Tests: {integration_result.testsRun} run, {len(integration_result.errors)} errors, {len(integration_result.failures)} failures")

    # Return non-zero exit code if any tests failed
    if unit_result.wasSuccessful() and integration_result.wasSuccessful():
        return 0
    else:
        return 1

if __name__ == '__main__':
    sys.exit(run_tests())

