import smtplib
from email.message import EmailMessage

def send_email(subject, html_content, from_addr='your_email@example.com', to_addr='coltinengle@gmail.com'):
    msg = EmailMessage()
    msg['Subject'] = subject
    msg['From'] = from_addr
    msg['To'] = to_addr
    msg.set_content(html_content, subtype='html')  # Set the email content to HTML

    with smtplib.SMTP('localhost') as smtp:
        smtp.send_message(msg)
        print("Email sent successfully!")

def format_html_email(title, message, title_bold=False, title_heading_level=None, message_bold=False, message_italic=False, table_data=None):
    # Apply title formatting
    if title_bold:
        title = f"<b>{title}</b>"
    if title_heading_level is not None:
        title = f"<h{title_heading_level}>{title}</h{title_heading_level}>"

    # Apply message formatting
    if message_bold:
        message = f"<b>{message}</b>"
    if message_italic:
        message = f"<i>{message}</i>"

    # Generate table HTML
    table_html = ""
    if table_data is not None:
        table_html = "<table>"
        for row in table_data:
            table_html += "<tr>"
            for cell in row:
                table_html += f"<td>{cell}</td>"
            table_html += "</tr>"
        table_html += "</table>"

    html_content = f"""
    <html>
    <head>
        <style>
            body {{ font-family: Arial, sans-serif; }}
            table {{ border-collapse: collapse; width: 100%; }}
            th, td {{ border: 1px solid #dddddd; text-align: left; padding: 8px; }}
            th {{ background-color: #f2f2f2; }}
        </style>
    </head>
    <body>
        {title}
        <p>{message}</p>
        {table_html}
    </body>
    </html>
    """
    return html_content

