def get_device_temperature():
    thermal_zone_path = '/sys/class/thermal'
    thermal_zones = []
    temperatures = []

    for zone_folder in os.listdir(thermal_zone_path):
        if zone_folder.startswith('thermal_zone'):
            temp_file = os.path.join(thermal_zone_path, zone_folder, 'temp')
            if os.path.isfile(temp_file):
                thermal_zones.append(temp_file)

    for zone in thermal_zones:
        command = f"cat {zone}"
        try:
            output = subprocess.run(command, capture_output=True, text=True, shell=True).stdout
            temperature = int(output) / 1000
            temperatures.append(temperature)
        except FileNotFoundError:
            write_to_log(f"Thermal zone file {zone} not found.")

    if temperatures:
        return max(temperatures)
    else:
        write_to_log("No thermal zone files found.")
        return None    
