def write_to_log(message):
    with open('/tmp/temperature.log', 'a') as log_file:
        log_file.write(message + '\n')

def monitor_device_temperature(threshold=80.0, duration_threshold=60):
    high_temp_start = None
    event_duration = 0
    while True:
        temperature = get_device_temperature()
        write_to_log(f"Current Device Temperature: {temperature}°C")

        if temperature > threshold:
            write_to_log("High temperature detected.")
            if high_temp_start is None:
                write_to_log("Starting hysteresis check...")
                # Perform hysteresis check
                hysteresis_count = 0
                for _ in range(5):
                    temperature = get_device_temperature()
                    if temperature > threshold:
                        hysteresis_count += 1
                    time.sleep(1)

                if hysteresis_count >= 3:
                    # Confirm high temperature for at least 3 out of 5 seconds
                    high_temp_start = time.time()  # Start the timer
                    write_to_log(f"High temperature event started at {time.ctime(high_temp_start)}")

                    subject = "High Temperature Alert"
                    message = "Current Temperature:\n"

                    table_data = [["Temperature", f"{temperature}°C"]]

                    html_email = format_html_email('', '', table_data=table_data)
                    send_email(subject, html_email)
                else:
                    write_to_log("Hysteresis check failed. High temperature not confirmed.")
            else:
                write_to_log("High temperature event in progress.")
                event_duration = time.time() - high_temp_start
            time.sleep(2)  # Poll every other second
        else:
            write_to_log("Temperature is below the threshold.")
            if high_temp_start is not None:
                event_duration += time.time() - high_temp_start
                write_to_log(f"High temperature event ended. Total duration: {event_duration} seconds")

                if event_duration >= duration_threshold:
                    subject = "Temperature Normalized"
                    title = f"High temperature lasted for {int(event_duration)} seconds."
                    message = ""

                    html_email = format_html_email(title, message, title_heading_level=2)
                    send_email(subject, html_email)
                    write_to_log(f"Followup email sent. Duration: {int(event_duration)} seconds")
                else:
                    write_to_log(f"High temperature event ended, but total duration ({event_duration} seconds) is below the threshold.")

                high_temp_start = None  # Reset the timer
                event_duration = 0  # Reset the event duration
            time.sleep(30)  # Check every 30 seconds if temperature is below threshold

monitor_device_temperature()
